# oncall/hypercare_exit_check.py
# Run all exit gates and return a structured pass/fail report.
import requests, datetime
from dataclasses import dataclass
from typing import List, Tuple

PROMETHEUS = 'http://prometheus:9090'
JIRA_BASE = 'https://jira.internal/rest/api/2'

@dataclass
class GateResult:
    name: str
    passed: bool
    value: str
    owner: str

def prom_query(q: str) -> float:
    r = requests.get(f'{PROMETHEUS}/api/v1/query',
                     params={'query': q}, timeout=5)
    result = r.json()['data']['result']
    return float(result[0]['value'][1]) if result else float('nan')

def check_eval_pass_rate() -> GateResult:
    v = prom_query('avg_over_time(eval_pass_rate[7d])')
    return GateResult(
        name='Eval pass rate (7d avg)',
        passed=v >= 0.94,
        value=f'{v:.1%}',
        owner='ML Platform',
    )

def check_safety_flag_rate() -> GateResult:
    v = prom_query(
        'rate(safety_flag_total[24h]) / rate(llm_request_total[24h])'
    )
    return GateResult(
        name='Safety flag rate (24h)',
        passed=v <= 0.0005,
        value=f'{v:.4%}',
        owner='Trust & Safety',
    )

def check_error_rate() -> GateResult:
    v = prom_query(
        'rate(http_requests_total{status=~"5.."}[1h])'
        ' / rate(http_requests_total[1h])'
    )
    return GateResult(
        name='Error rate (1h)',
        passed=v <= 0.001,
        value=f'{v:.4%}',
        owner='SRE',
    )

def check_open_pirs() -> GateResult:
    # Check for unresolved P0/P1 PIR tickets in Jira
    r = requests.get(
        f'{JIRA_BASE}/search',
        params={'jql': 'labels=PIR AND priority in (P0,P1) AND status!=Done'},
        timeout=10,
    )
    open_count = r.json()['total']
    return GateResult(
        name='Open PIR action items',
        passed=open_count == 0,
        value=str(open_count),
        owner='Feature team',
    )

def run_exit_check() -> Tuple[bool, List[GateResult]]:
    gates = [
        check_eval_pass_rate(),
        check_safety_flag_rate(),
        check_error_rate(),
        check_open_pirs(),
    ]
    all_pass = all(g.passed for g in gates)
    return all_pass, gates

if __name__ == '__main__':
    ok, results = run_exit_check()
    for g in results:
        icon = 'PASS' if g.passed else 'FAIL'
        print(f'{icon}  {g.name}: {g.value} (owner: {g.owner})')
    print()
    if ok:
        print('All gates pass — hypercare may exit')
    else:
        failing = [g.name for g in results if not g.passed]
        print(f'EXTEND hypercare: {len(failing)} gate(s) failing: {failing}')
    raise SystemExit(0 if ok else 1)
